<!doctype html><html lang="zh-CN"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>DepartmentIFO</title><script src="/DepartmentIFO/auth-monitor/sdk/js/auth-monitor.min.js"></script><style>
:root{--bg:#f4f7fb;--panel:#fff;--text:#172033;--muted:#667085;--line:#d9e2ef;--brand:#0f766e;--brand2:#1d4ed8;--danger:#dc2626;--warn:#b45309;--ok:#15803d;--side:#101828}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font-family:Arial,"Microsoft YaHei",sans-serif}.login-page{min-height:100vh;display:grid;grid-template-columns:1.15fr .85fr;background:#0b1220}.login-visual{position:relative;padding:56px;color:#fff;display:flex;flex-direction:column;justify-content:space-between;background:linear-gradient(135deg,#0f766e 0%,#1d4ed8 55%,#172033 100%)}.login-visual h1{font-size:42px;margin:0 0 18px}.login-visual p{font-size:17px;line-height:1.8;max-width:620px;color:#e9f2ff}.login-stats{display:grid;grid-template-columns:repeat(3,1fr);gap:14px}.login-stat{border:1px solid rgba(255,255,255,.28);padding:18px;border-radius:8px;background:rgba(255,255,255,.08)}.login-stat b{display:block;font-size:26px}.login-box{background:#fff;display:flex;align-items:center;justify-content:center;padding:32px}.login-card{width:min(420px,100%)}.login-card h2{font-size:28px;margin:0 0 8px}.login-card .hint{color:var(--muted);margin-bottom:28px}.field{margin-bottom:14px}.field label{display:block;font-weight:700;margin-bottom:7px}.field input,.field select,.field textarea{width:100%;padding:12px;border:1px solid var(--line);border-radius:6px;font-size:14px;background:#fff}.btn{border:0;border-radius:6px;padding:11px 14px;background:var(--brand2);color:white;cursor:pointer;font-weight:700}.btn.secondary{background:#eef4ff;color:#1d4ed8}.btn.danger{background:#fee2e2;color:#b91c1c}.btn.ok{background:#dcfce7;color:#166534}.btn.block{width:100%;font-size:15px}.err{color:#b91c1c;min-height:22px}.app{display:grid;grid-template-columns:250px 1fr;min-height:100vh}.side{background:var(--side);color:white;padding:20px 14px}.brand{font-size:18px;font-weight:800;padding:8px 10px 20px}.nav button{width:100%;display:flex;align-items:center;gap:9px;border:0;background:transparent;color:#cbd5e1;padding:12px 10px;border-radius:6px;cursor:pointer;text-align:left;font-size:14px}.nav button.active,.nav button:hover{background:#1e293b;color:#fff}.main{min-width:0}.top{height:64px;background:white;border-bottom:1px solid var(--line);display:flex;align-items:center;justify-content:space-between;padding:0 24px}.top h2{margin:0;font-size:18px}.content{padding:22px}.cards{display:grid;grid-template-columns:repeat(5,minmax(140px,1fr));gap:14px;margin-bottom:16px}.card{background:var(--panel);border:1px solid var(--line);border-radius:8px;padding:16px}.card .label{color:var(--muted);font-size:13px}.card .num{font-size:30px;font-weight:800;margin-top:8px}.grid2{display:grid;grid-template-columns:1.25fr .75fr;gap:16px}.toolbar{display:flex;gap:10px;flex-wrap:wrap;align-items:center;margin-bottom:12px}.toolbar input,.toolbar select{padding:10px;border:1px solid var(--line);border-radius:6px}table{width:100%;border-collapse:collapse;background:white;border:1px solid var(--line);border-radius:8px;overflow:hidden}th,td{border-bottom:1px solid #edf2f7;padding:11px;text-align:left;font-size:14px}th{background:#f8fafc;color:#475467}.pill{display:inline-block;border-radius:999px;padding:4px 9px;font-size:12px;background:#eef2ff;color:#3730a3}.pill.ok{background:#dcfce7;color:#166534}.pill.off{background:#fee2e2;color:#991b1b}.section-title{display:flex;justify-content:space-between;align-items:center;margin-bottom:12px}.section-title h3{margin:0}.tree{display:grid;grid-template-columns:repeat(4,minmax(160px,1fr));gap:12px}.dept-card{border-left:4px solid var(--brand);background:white;border-radius:8px;border-top:1px solid var(--line);border-right:1px solid var(--line);border-bottom:1px solid var(--line);padding:15px}.score{height:8px;background:#e5e7eb;border-radius:999px;overflow:hidden}.score span{display:block;height:100%;background:linear-gradient(90deg,var(--brand),var(--brand2))}.empty{color:var(--muted);padding:20px;text-align:center}.modal{position:fixed;inset:0;background:rgba(15,23,42,.45);display:none;align-items:center;justify-content:center;padding:20px}.modal.show{display:flex}.modal-card{background:white;border-radius:8px;width:min(720px,100%);padding:22px}.form-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}@media(max-width:980px){.login-page{grid-template-columns:1fr}.login-visual{min-height:360px}.app{grid-template-columns:1fr}.side{position:sticky;top:0;z-index:2}.nav{display:grid;grid-template-columns:repeat(3,1fr);gap:6px}.cards{grid-template-columns:repeat(2,1fr)}.grid2{grid-template-columns:1fr}.tree{grid-template-columns:1fr 1fr}}@media(max-width:620px){.content{padding:14px}.cards,.tree,.form-grid{grid-template-columns:1fr}.login-visual{padding:32px}.login-visual h1{font-size:30px}.login-stats{grid-template-columns:1fr}}
</style></head><body><div id="root"></div><div id="modal" class="modal"><div class="modal-card" id="modalCard"></div></div><script>
AuthMonitor.init({appId:'member-platform',apiBase:'/DepartmentIFO/auth-monitor/api/v1',autoTrack:true});
const C={loginTitle:'\u90e8\u95e8\u6210\u5458\u7ba1\u7406\u5e73\u53f0',loginSub:'\u7edf\u4e00\u8eab\u4efd\u8ba4\u8bc1\u3001\u7ec4\u7ec7\u67b6\u6784\u3001\u6210\u5458\u6863\u6848\u3001\u8003\u6838\u8bc4\u4ef7\u4e0e\u63a5\u53e3\u76d1\u63a7\u4e00\u4f53\u5316',login:'\u767b\u5f55',account:'\u5b66\u53f7 / \u8d26\u53f7',password:'\u5bc6\u7801',dashboard:'\u6570\u636e\u770b\u677f',members:'\u6210\u5458\u6863\u6848',org:'\u7ec4\u7ec7\u67b6\u6784',eval:'\u8003\u6838\u8bc4\u4ef7',approval:'\u5ba1\u6279\u4e2d\u5fc3',imports:'\u6279\u91cf\u5bfc\u5165',audit:'\u64cd\u4f5c\u65e5\u5fd7',logout:'\u9000\u51fa',total:'\u6210\u5458\u603b\u6570',active:'\u5728\u804c\u6210\u5458',disabled:'\u505c\u7528\u6210\u5458',pending:'\u5f85\u5ba1\u6279',avg:'\u5e73\u5747\u8003\u6838',name:'\u59d3\u540d',stuno:'\u5b66\u53f7',department:'\u90e8\u95e8',post:'\u804c\u52a1',status:'\u72b6\u6001',actions:'\u64cd\u4f5c',add:'\u65b0\u589e',search:'\u641c\u7d22',disable:'\u505c\u7528',restore:'\u6062\u590d',upload:'\u4e0a\u4f20\u9884\u89c8'};
let token=localStorage.getItem('mp_token');let state={page:'dashboard',members:[],overview:null,org:null,evals:null};
function api(path,opt={}){opt.headers=Object.assign({'Content-Type':'application/json','Authorization':'Bearer '+token},opt.headers||{});return fetch('/DepartmentIFO/member-platform/api'+path,opt).then(r=>r.json())}
function root(){return document.getElementById('root')}function esc(s){return String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]))}function statusPill(s){return s==='active'?`<span class="pill ok">\u5728\u804c</span>`:s==='disabled'?`<span class="pill off">\u505c\u7528</span>`:`<span class="pill">${esc(s)}</span>`}
function renderLogin(){root().innerHTML=`<div class="login-page"><section class="login-visual"><div><h1>${C.loginTitle}</h1><p>${C.loginSub}</p></div><div class="login-stats"><div class="login-stat"><b>Auth</b><span>Token SDK</span></div><div class="login-stat"><b>API</b><span>Monitor</span></div><div class="login-stat"><b>IFO</b><span>Member OS</span></div></div></section><section class="login-box"><div class="login-card"><h2>${C.login}</h2><div class="hint">\u8bf7\u4f7f\u7528\u7ba1\u7406\u5458\u8d26\u53f7\u6216\u6210\u5458\u5b66\u53f7\u767b\u5f55</div><div class="field"><label>${C.account}</label><input id="u" autocomplete="username"></div><div class="field"><label>${C.password}</label><input id="p" type="password" autocomplete="current-password"></div><button class="btn block" onclick="loginNow()">${C.login}</button><p class="err" id="loginMsg"></p></div></section></div>`}
function shell(){root().innerHTML=`<div class="app"><aside class="side"><div class="brand">DepartmentIFO</div><nav class="nav">${[['dashboard',C.dashboard],['members',C.members],['org',C.org],['eval',C.eval],['approval',C.approval],['imports',C.imports],['audit',C.audit]].map(x=>`<button class="${state.page===x[0]?'active':''}" onclick="go('${x[0]}')">${x[1]}</button>`).join('')}</nav></aside><main class="main"><div class="top"><h2>${pageTitle()}</h2><div><span class="pill ok">\u5df2\u767b\u5f55</span> <button class="btn secondary" onclick="logoutNow()">${C.logout}</button></div></div><div class="content" id="content"></div></main></div>`;loadPage()}
function pageTitle(){return {dashboard:C.dashboard,members:C.members,org:C.org,eval:C.eval,approval:C.approval,imports:C.imports,audit:C.audit}[state.page]||C.dashboard}function go(p){state.page=p;shell()}function loginNow(){fetch('/DepartmentIFO/member-platform/api/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username:u.value,password:p.value})}).then(r=>r.json()).then(d=>{if(d.ok){token=d.access_token;localStorage.setItem('mp_token',token);AuthMonitor.setToken(token);shell()}else loginMsg.textContent=d.message||'\u767b\u5f55\u5931\u8d25'})}function logoutNow(){localStorage.removeItem('mp_token');location.reload()}
function loadPage(){({dashboard:loadDashboard,members:loadMembers,org:loadOrg,eval:loadEval,approval:loadApprovals,imports:loadImports,audit:loadAudit}[state.page]||loadDashboard)()}
function loadDashboard(){api('/dashboard/overview').then(d=>{let c=document.getElementById('content');c.innerHTML=`<div class="cards"><div class="card"><div class="label">${C.total}</div><div class="num">${d.total}</div></div><div class="card"><div class="label">${C.active}</div><div class="num">${d.active}</div></div><div class="card"><div class="label">${C.disabled}</div><div class="num">${d.disabled}</div></div><div class="card"><div class="label">${C.pending}</div><div class="num">${d.pending_approvals}</div></div><div class="card"><div class="label">${C.avg}</div><div class="num">${d.avg_score}</div></div></div><div class="grid2"><div class="card"><div class="section-title"><h3>\u90e8\u95e8\u4eba\u6570\u5206\u5e03</h3></div>${(d.departments||[]).map(x=>`<p>${esc(x.name)} <span class="pill">${x.c}</span></p>`).join('')}</div><div class="card"><h3>\u6700\u8fd1\u64cd\u4f5c</h3>${(d.recent||[]).map(x=>`<p><b>${esc(x.actor)}</b> ${esc(x.action)}<br><span class="label">${x.created_at}</span></p>`).join('')||'<div class="empty">\u6682\u65e0\u8bb0\u5f55</div>'}</div></div>`})}
function loadMembers(){api('/members').then(d=>{state.members=d.data||[];document.getElementById('content').innerHTML=`<div class="toolbar"><input id="q" placeholder="\u641c\u7d22\u59d3\u540d\u3001\u5b66\u53f7\u3001\u90e8\u95e8"><button class="btn" onclick="searchMembers()">${C.search}</button><button class="btn secondary" onclick="openMemberForm()">${C.add}${C.members}</button><a class="btn secondary" href="/DepartmentIFO/member-platform/api/export/members" target="_blank">\u5bfc\u51fa</a></div><table><thead><tr><th>${C.name}</th><th>${C.stuno}</th><th>${C.department}</th><th>${C.post}</th><th>${C.status}</th><th>${C.actions}</th></tr></thead><tbody>${state.members.map(m=>`<tr><td>${esc(m.name)}</td><td>${esc(m.stuno)}</td><td>${esc(m.bm)}</td><td>${esc(m.posts)}</td><td>${statusPill(m.status)}</td><td><button class="btn danger" onclick="disableMember(${m.id})">${C.disable}</button> <button class="btn ok" onclick="restoreMember(${m.id})">${C.restore}</button></td></tr>`).join('')}</tbody></table>`})}function searchMembers(){api('/members?q='+encodeURIComponent(q.value)).then(d=>{state.members=d.data||[];loadMembersTableOnly()})}function loadMembersTableOnly(){loadMembers()}function disableMember(id){api('/members/'+id+'/disable',{method:'POST',body:'{}'}).then(loadMembers)}function restoreMember(id){api('/members/'+id+'/restore',{method:'POST',body:'{}'}).then(loadMembers)}function openMemberForm(){modal(`<h3>${C.add}${C.members}</h3><div class="form-grid"><div class="field"><label>${C.name}</label><input id="mn"></div><div class="field"><label>${C.stuno}</label><input id="ms"></div><div class="field"><label>${C.department}</label><input id="mb"></div><div class="field"><label>${C.post}</label><input id="mpo"></div></div><button class="btn" onclick="saveMember()">\u4fdd\u5b58</button> <button class="btn secondary" onclick="closeModal()">\u53d6\u6d88</button>`)}function saveMember(){api('/members',{method:'POST',body:JSON.stringify({name:mn.value,stuno:ms.value,bm:mb.value,posts:mpo.value})}).then(()=>{closeModal();loadMembers()})}
function loadOrg(){api('/organization/summary').then(d=>{document.getElementById('content').innerHTML=`<div class="section-title"><h3>${C.org}</h3><button class="btn secondary" onclick="openDeptForm()">\u65b0\u589e\u90e8\u95e8</button></div><div class="tree">${(d.departments||[]).map(x=>`<div class="dept-card"><h3>${esc(x.name)}</h3><p>\u6210\u5458\u6570\uff1a<b>${x.member_count}</b></p><p>\u5728\u804c\uff1a<b>${x.active_count||0}</b></p></div>`).join('')}</div><div class="card" style="margin-top:16px"><h3>\u804c\u52a1\u5206\u5e03</h3>${(d.posts||[]).map(x=>`<p>${esc(x.name)} <span class="pill">${x.c}</span></p>`).join('')}</div>`})}function openDeptForm(){modal(`<h3>\u65b0\u589e\u90e8\u95e8</h3><div class="field"><label>\u90e8\u95e8\u540d\u79f0</label><input id="dn"></div><button class="btn" onclick="saveDept()">\u4fdd\u5b58</button> <button class="btn secondary" onclick="closeModal()">\u53d6\u6d88</button>`)}function saveDept(){api('/departments',{method:'POST',body:JSON.stringify({name:dn.value})}).then(()=>{closeModal();loadOrg()})}
function loadEval(){Promise.all([api('/evaluations'),api('/evaluations/summary'),api('/members')]).then(([e,s,m])=>{state.members=m.data||[];document.getElementById('content').innerHTML=`<div class="section-title"><h3>${C.eval}</h3><button class="btn" onclick="openEvalForm()">\u65b0\u589e\u8bc4\u4ef7</button></div><div class="grid2"><div class="card"><h3>\u90e8\u95e8\u5747\u5206</h3>${(s.data||[]).map(x=>`<p>${esc(x.department)} ${x.avg_score||0}</p><div class="score"><span style="width:${Math.min(100,x.avg_score||0)}%"></span></div>`).join('')}</div><div class="card"><h3>\u8bc4\u4ef7\u89c4\u5219</h3><p>\u5de5\u4f5c\u8d28\u91cf\u3001\u7eaa\u5f8b\u6267\u884c\u3001\u534f\u4f5c\u8d21\u732e\u3001\u6210\u957f\u8868\u73b0\u5404 25 \u5206\u3002</p></div></div><table style="margin-top:16px"><thead><tr><th>${C.name}</th><th>${C.department}</th><th>\u603b\u5206</th><th>\u7b49\u7ea7</th><th>\u8bc4\u4ef7\u4eba</th><th>\u65f6\u95f4</th></tr></thead><tbody>${(e.data||[]).map(x=>`<tr><td>${esc(x.member_name)}</td><td>${esc(x.bm)}</td><td>${x.total_score}</td><td><span class="pill ok">${esc(x.level)}</span></td><td>${esc(x.evaluator)}</td><td>${x.created_at}</td></tr>`).join('')}</tbody></table>`})}function openEvalForm(){modal(`<h3>\u65b0\u589e\u8003\u6838\u8bc4\u4ef7</h3><div class="field"><label>${C.members}</label><select id="em">${state.members.map(m=>`<option value="${m.id}">${esc(m.name)} - ${esc(m.stuno)}</option>`).join('')}</select></div><div class="form-grid"><div class="field"><label>\u5de5\u4f5c\u8d28\u91cf</label><input id="s1" type="number" value="22"></div><div class="field"><label>\u7eaa\u5f8b\u6267\u884c</label><input id="s2" type="number" value="22"></div><div class="field"><label>\u534f\u4f5c\u8d21\u732e</label><input id="s3" type="number" value="22"></div><div class="field"><label>\u6210\u957f\u8868\u73b0</label><input id="s4" type="number" value="22"></div></div><div class="field"><label>\u8bc4\u8bed</label><textarea id="ec"></textarea></div><button class="btn" onclick="saveEval()">\u4fdd\u5b58</button> <button class="btn secondary" onclick="closeModal()">\u53d6\u6d88</button>`)}function saveEval(){api('/evaluations',{method:'POST',body:JSON.stringify({member_id:em.value,work_score:s1.value,discipline_score:s2.value,collaboration_score:s3.value,growth_score:s4.value,comment:ec.value})}).then(()=>{closeModal();loadEval()})}
function loadApprovals(){api('/approvals').then(d=>{document.getElementById('content').innerHTML=`<div class="section-title"><h3>${C.approval}</h3><button class="btn" onclick="openApprovalForm()">\u53d1\u8d77\u7533\u8bf7</button></div><table><thead><tr><th>\u6807\u9898</th><th>\u7c7b\u578b</th><th>\u7533\u8bf7\u4eba</th><th>${C.status}</th><th>\u65f6\u95f4</th></tr></thead><tbody>${(d.data||[]).map(x=>`<tr><td>${esc(x.title)}</td><td>${esc(x.type)}</td><td>${esc(x.applicant_stuno)}</td><td><span class="pill">${x.status}</span></td><td>${x.created_at}</td></tr>`).join('')}</tbody></table>`})}function openApprovalForm(){modal(`<h3>\u53d1\u8d77\u7533\u8bf7</h3><div class="field"><label>\u7533\u8bf7\u6807\u9898</label><input id="at"></div><div class="field"><label>\u7533\u8bf7\u7c7b\u578b</label><select id="ay"><option value="join">\u5165\u90e8</option><option value="leave">\u79bb\u90e8</option><option value="transfer">\u8c03\u5c97</option><option value="profile">\u4fe1\u606f\u4fee\u6539</option></select></div><button class="btn" onclick="saveApproval()">\u63d0\u4ea4</button> <button class="btn secondary" onclick="closeModal()">\u53d6\u6d88</button>`)}function saveApproval(){api('/approvals',{method:'POST',body:JSON.stringify({title:at.value,type:ay.value})}).then(()=>{closeModal();loadApprovals()})}
function loadImports(){document.getElementById('content').innerHTML=`<div class="card"><h3>${C.imports}</h3><p>\u652f\u6301 CSV / XLS / XLSX\uff0c\u5148\u9884\u89c8\u6821\u9a8c\uff0c\u518d\u786e\u8ba4\u5165\u5e93\u3002</p><input type="file" id="file"><button class="btn" onclick="previewImport()">${C.upload}</button><pre id="importResult"></pre></div>`}function previewImport(){let fd=new FormData();fd.append('file',file.files[0]);fetch('/DepartmentIFO/member-platform/api/imports/preview',{method:'POST',headers:{'Authorization':'Bearer '+token},body:fd}).then(r=>r.json()).then(d=>importResult.textContent=JSON.stringify(d,null,2))}
function loadAudit(){api('/audit-logs').then(d=>{document.getElementById('content').innerHTML=`<table><thead><tr><th>\u64cd\u4f5c\u4eba</th><th>\u52a8\u4f5c</th><th>\u5bf9\u8c61</th><th>\u8be6\u60c5</th><th>\u65f6\u95f4</th></tr></thead><tbody>${(d.data||[]).map(x=>`<tr><td>${esc(x.actor)}</td><td>${esc(x.action)}</td><td>${esc(x.target_type)} #${esc(x.target_id)}</td><td>${esc(x.detail)}</td><td>${x.created_at}</td></tr>`).join('')}</tbody></table>`})}
function modal(html){document.getElementById('modalCard').innerHTML=html;document.getElementById('modal').classList.add('show')}function closeModal(){document.getElementById('modal').classList.remove('show')}if(token)shell();else renderLogin();
</script></body></html>
